def kth_ordered(words, k):
    if not words or k <= 0:
        return None

    # Group words by their length
    grouped = {}
    for word in words:
        length = len(word)
        if length not in grouped:
            grouped[length] = []
        grouped[length].append(word)

    ordered_words = []
    for length, group in sorted(grouped.items(), key=lambda x: (x[0], -ord(x[1][0]))):
        ordered_words.extend(sorted(group, reverse=True))

    if k > len(ordered_words):
        return None

    return ordered_words[k-1]
